"use strict";(globalThis.webpackChunk_servicenow_sdk_docs=globalThis.webpackChunk_servicenow_sdk_docs||[]).push([[18044],{8791(s){s.exports=JSON.parse('{"tag":{"label":"now assist","permalink":"/sdk/4.6.0/tags/now-assist","allTagsPath":"/sdk/4.6.0/tags","count":2,"items":[{"id":"guides/nowassist-skills-guide","title":"Now Assist Skills Guide","description":"Create and configure Now Assist Skills using the NowAssistSkillConfig API in the Fluent SDK. Skills use configured prompts to generate AI responses from an LLM, optionally enriched by inputs and tools (script, inline script, web search, subflows, flow actions, decision branches). This guide covers the full lifecycle: provider/model selection, input configuration, tool wiring, prompt authoring, security controls, and deployment. Requires SDK 4.6.0 or higher.","permalink":"/sdk/4.6.0/guides/nowassist-skills-guide"},{"id":"api/nowassistskillconfig-api","title":"NowAssistSkillConfig","description":"Creates a NowAssist Skill configuration for building AI-powered skills on the ServiceNow platform using the Fluent API. A NowAssist Skill Config defines the complete skill setup \u2014 including metadata, inputs, outputs, tool integrations, LLM provider and prompt configurations, and security controls \u2014 so that it can be built as a NowAssist skill. Use this when you want to define a generative AI skill as source-driven code instead of configuring it manually through the Skill Builder UI.","permalink":"/sdk/4.6.0/api/nowassistskillconfig-api"}],"unlisted":false}}')}}]);